import java.util.*;class A{static String[]R=new String[4];static int PL,NB,MB;static boolean h0(int i,int a,int b){for(int j=a;j<b&&j<PL;j++)if(R[i].charAt(j)=='0')return true;return false;}static int[]sim(int[]L,int x,int sp,String act){int[]n=L.clone();if(act.equals("SPEED"))sp++;if(act.equals("SLOW"))sp--;if(act.equals("SPEED")||act.equals("SLOW")||act.equals("WAIT")){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,x,x+sp))n[i]=0;x+=sp;}else if(act.equals("JUMP")){for(int i=0;i<4;i++)if(n[i]==1&&(R[i].charAt(x)=='0'||(x+sp<PL&&R[i].charAt(x+sp)=='0')))n[i]=0;x+=sp;}else if(act.equals("UP")){if(n[0]==1){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,x,x+sp))n[i]=0;}else for(int i=1;i<4;i++){if(n[i-1]==0&&n[i]==1){if(h0(i-1,x,x+sp)||h0(i,x,x+sp)){n[i-1]=0;n[i]=0;}else{n[i-1]=1;n[i]=0;}}else if(n[i-1]==1&&n[i]==1){if(h0(i-1,x,x+sp))n[i-1]=0;if(h0(i,x,x+sp))n[i]=0;}}x+=sp;}else{if(n[3]==1){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,x,x+sp))n[i]=0;}else for(int i=2;i>=0;i--){if(n[i+1]==0&&n[i]==1){if(h0(i,x,x+sp)||h0(i+1,x,x+sp)){n[i+1]=0;n[i]=0;}else{n[i+1]=1;n[i]=0;}}else if(n[i+1]==1&&n[i]==1){if(h0(i+1,x,x+sp))n[i+1]=0;if(h0(i,x,x+sp))n[i]=0;}}x+=sp;}return new int[]{n[0],n[1],n[2],n[3],x,sp};}public static void main(String[]args){var s=new Scanner(System.in);NB=s.nextInt();MB=s.nextInt();s.nextLine();for(int i=0;i<4;i++)R[i]=s.nextLine()+".".repeat(50);PL=R[0].length();var F=new ArrayList<String>();String[]acts={"SPEED","JUMP","WAIT","UP","DOWN","SLOW"};for(;;){if(!F.isEmpty()){s.nextInt();for(int i=0;i<NB;i++){s.nextInt();s.nextInt();s.nextInt();}System.out.println(F.remove(0));continue;}int sp=s.nextInt();int[]L=new int[4];int bx=0;for(int i=0;i<NB;i++){int x=s.nextInt(),y=s.nextInt(),a=s.nextInt();L[y]=a;if(a==1)bx=x;}var q=new ArrayList<int[][]>();q.add(new int[][]{L.clone(),{bx,sp,0}});int[]best=null;List<String>ba=null;for(int it=0;it<30&&!q.isEmpty();it++){var nq=new ArrayList<int[][]>();var na2=new ArrayList<List<String>>();for(int qi=0;qi<q.size();qi++){var st=q.get(qi);for(var act:acts){var r=sim(new int[]{st[0][0],st[0][1],st[0][2],st[0][3]},st[1][0],st[1][1],act);int nb=r[0]+r[1]+r[2]+r[3];if(nb<MB||r[5]<1)continue;var ca=new ArrayList<>(na2.size()>qi?na2.get(qi):List.<String>of());ca.add(act);if(r[4]>=PL-30){if(best==null||nb>best[0]+best[1]+best[2]+best[3]){best=r;ba=ca;}continue;}nq.add(new int[][]{{r[0],r[1],r[2],r[3]},{r[4],r[5],0}});na2.add(ca);}}if(nq.size()>200){nq.subList(200,nq.size()).clear();na2.subList(200,na2.size()).clear();}q=nq;if(best!=null)break;}F=ba!=null?new ArrayList<>(ba):new ArrayList<>(List.of("SPEED"));System.out.println(F.remove(0));}}}